('cmoypkyxa03acsmvm788i03wt', 'cmoypkyxa03aasmvmkdkjcjwx', 'cmnulzbhs0002qlkkruq7oxyc', NULL, 'cmnulzkee000fqlkkz5pegb2b', NULL, NULL, NULL, '3 de agosto - 20:00 hXabier Anduaga (tenor) y Hera Hyesang Park (soprano invitada)CICLO AURA – en el Teatro Colon Programación Ciclo Aura 2026 Consegui tus entradasOrquesta del Ciclo Aura Dirección: Constantine Orbelian El CICLO AURA regresa en 2026 a la Sala Principal del Teatro Colón para una nueva temporada que reunirá a intérpretes ex cepcionales de la escena musical internacional, como Maxim Vengerov, Pinchas Zukerman, Freddie De Tommaso y el regreso de Nadine Sierra, entre otros. Serán cuatro conciertos a lo largo del año, cuatro noches únicas para vivir la música en su máxima expresión, en uno de los escenarios más prestigiosos del mundo.En esta ocasión, el CICLO AURA -una coproducción entre el Teatro Colón, Mama Hungara Live y Elisa Wagner ICP- presenta una programación de excelencia que combina conciertos sinfónicos, recitales instrumentales y galas líricas, acercando al público a los grandes intérpretes de la música clásica actual. Para la temporada 2026 se anuncia la creación de la Orquesta del Ciclo Aura, una formación especialmente concebida para el proyecto que participará en dos de las cuatro fechas. Este hito consolida la identidad artística del ciclo, refuerza su perfil sinfónico y su proyección institucional y cultural.', 'ANY', 'ANY', NULL, NULL, 'CUOTAS_SIN_INTERES', 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('cmoypkyxa03adsmvm2kq1pauu', 'cmoypkyxa03aasmvmkdkjcjwx', 'cmnulzbhs0002qlkkruq7oxyc', NULL, 'cmnulzllo000gqlkkod8d8w5l', NULL, NULL, NULL, '3 de agosto - 20:00 hXabier Anduaga (tenor) y Hera Hyesang Park (soprano invitada)CICLO AURA – en el Teatro Colon Programación Ciclo Aura 2026 Consegui tus entradasOrquesta del Ciclo Aura Dirección: Constantine Orbelian El CICLO AURA regresa en 2026 a la Sala Principal del Teatro Colón para una nueva temporada que reunirá a intérpretes ex cepcionales de la escena musical internacional, como Maxim Vengerov, Pinchas Zukerman, Freddie De Tommaso y el regreso de Nadine Sierra, entre otros. Serán cuatro conciertos a lo largo del año, cuatro noches únicas para vivir la música en su máxima expresión, en uno de los escenarios más prestigiosos del mundo.En esta ocasión, el CICLO AURA -una coproducción entre el Teatro Colón, Mama Hungara Live y Elisa Wagner ICP- presenta una programación de excelencia que combina conciertos sinfónicos, recitales instrumentales y galas líricas, acercando al público a los grandes intérpretes de la música clásica actual. Para la temporada 2026 se anuncia la creación de la Orquesta del Ciclo Aura, una formación especialmente concebida para el proyecto que participará en dos de las cuatro fechas. Este hito consolida la identidad artística del ciclo, refuerza su perfil sinfónico y su proyección institucional y cultural.', 'ANY', 'ANY', NULL, NULL, 'CUOTAS_SIN_INTERES', 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
